    let two_n = 2 * n

    // Initialize the result array ans of size 2n
    var ans: Array<Int64> = new Array<Int64>(two_n)

    // 1. Copy nums to the first n elements
    for i in 0..<n {
        ans[i] = nums[i]
    }

    // 2. Copy nums in reverse order to the last n elements
    for i in 0..<n {
        // The index in nums corresponding to the i-th element of the reversed sequence is n - 1 - i
        let reverse_index = n - 1 - i
        // This element goes into ans at index i + n
        ans[i + n] = nums[reverse_index]
    }

    return ans
}

